{
  "executive_summary": "Architecture for a real-time ML delivery time estimation service with a decoupled training pipeline, model registry with versioned rollback, and a low-latency inference service behind a feature store. The design separates the hot path (prediction at checkout) from the cold path (weekly retraining) to independently optimize latency and throughput. Sized for a 4-person team — favors managed services and simplicity over custom infrastructure.",

  "architecture": {
    "components": [
      {
        "name": "Inference Service",
        "responsibility": "Serves predictions at <100ms P99. Loads the active model version from the Model Registry, accepts feature vectors, returns predicted delivery time in minutes. Stateless, horizontally scalable.",
        "boundaries": "Owns only prediction logic. Does NOT train models, compute features from raw data, or persist delivery outcomes. Receives pre-computed features from Feature Service."
      },
      {
        "name": "Feature Service",
        "responsibility": "Computes and serves real-time feature vectors (weight, distance, zone, time-of-day, weather, courier load) for both training and inference. Maintains a feature store with online (low-latency lookups) and offline (batch for training) serving layers.",
        "boundaries": "Owns feature definitions, transformations, and consistency between training and serving. Does NOT own raw data ingestion or model logic."
      },
      {
        "name": "Training Pipeline",
        "responsibility": "Weekly batch job that pulls historical delivery data + features from the offline feature store, trains a new model, validates it against holdout data and the current production model, and registers the candidate in the Model Registry.",
        "boundaries": "Runs on a schedule (cron/orchestrator). Has no runtime coupling to the Inference Service. Produces a versioned model artifact — nothing more."
      },
      {
        "name": "Model Registry",
        "responsibility": "Versioned store for trained model artifacts with metadata (metrics, training date, dataset hash, status: candidate/active/rolled-back). Supports promotion and rollback operations.",
        "boundaries": "Owns model lifecycle state. Does NOT decide whether to promote — that's the Validation Gate's job (or a human operator)."
      },
      {
        "name": "Validation Gate",
        "responsibility": "Automated quality gate that compares a candidate model against the active model on holdout metrics (MAE, P95 error, latency). Can auto-promote if thresholds pass, or flag for human review. Triggers rollback if post-deploy monitoring detects degradation.",
        "boundaries": "Owns promotion/rollback decision logic. Operates between Training Pipeline and Model Registry."
      },
      {
        "name": "Data Ingestion Layer",
        "responsibility": "Captures delivery outcome data (actual delivery times) and feeds it back into the offline feature store for future training. Also ingests real-time signals (weather API, courier load from dispatch system).",
        "boundaries": "Owns raw data capture and normalization. Downstream of operational systems, upstream of Feature Service."
      },
      {
        "name": "Monitoring & Observability",
        "responsibility": "Tracks prediction accuracy (predicted vs actual delivery time), model drift, feature drift, latency SLOs, and error rates. Triggers alerts and can initiate automatic rollback via the Validation Gate.",
        "boundaries": "Read-only observer of all other components. Publishes alerts and dashboards — does not mutate system state directly (rollback is triggered through Validation Gate API)."
      }
    ],
    "interfaces": [
      {
        "from": "Checkout API (external)",
        "to": "Inference Service",
        "contract": "POST /predict {order_id, weight_kg, origin_zone, dest_zone, distance_km} → {predicted_minutes, confidence_interval, model_version}",
        "coupling_type": "synchronous HTTP — tight latency coupling, must be <100ms P99 end-to-end"
      },
      {
        "from": "Inference Service",
        "to": "Feature Service",
        "contract": "GET /features/online {order_id, zone, timestamp} → {feature_vector} — precomputed weather + courier load joined with request-time features",
        "coupling_type": "synchronous HTTP/gRPC — co-located or in-memory cache to stay within latency budget"
      },
      {
        "from": "Inference Service",
        "to": "Model Registry",
        "contract": "Pull active model artifact on startup and on promotion events (push notification or polling). No per-request calls.",
        "coupling_type": "loose — model loaded into memory, registry is not on the hot path"
      },
      {
        "from": "Training Pipeline",
        "to": "Feature Service (offline)",
        "contract": "Batch read of historical feature vectors + delivery outcomes as Parquet/CSV dataset",
        "coupling_type": "loose — batch, async, no latency constraint"
      },
      {
        "from": "Training Pipeline",
        "to": "Model Registry",
        "contract": "PUT /models/{version} with artifact + metrics metadata",
        "coupling_type": "loose — async, post-training"
      },
      {
        "from": "Validation Gate",
        "to": "Model Registry",
        "contract": "PATCH /models/{version}/status {active|rolled-back} — promotes or rolls back",
        "coupling_type": "loose — event-driven or operator-triggered"
      },
      {
        "from": "Monitoring",
        "to": "Validation Gate",
        "contract": "POST /rollback {model_version, reason} when drift or accuracy degradation detected",
        "coupling_type": "loose — async alert-driven"
      },
      {
        "from": "Data Ingestion Layer",
        "to": "Feature Service (offline store)",
        "contract": "Batch append of delivery outcomes + enriched features on a continuous or daily cadence",
        "coupling_type": "loose — async batch"
      }
    ],
    "data_flow": "HOT PATH (checkout, <100ms): Checkout API → Inference Service → Feature Service (online, cached) → model inference → response. The Inference Service holds the model in-process memory (no network call to model registry per request). Feature Service pre-computes weather and courier load into a low-latency store (Redis/DynamoDB) updated every 1-5 minutes. COLD PATH (weekly): Data Ingestion captures delivery outcomes → Offline Feature Store builds training dataset → Training Pipeline trains candidate model → Validation Gate evaluates → Model Registry promotes → Inference Service hot-reloads new model (blue-green or rolling). FEEDBACK LOOP: Actual delivery times flow back through Data Ingestion, closing the loop for the next training cycle.",
    "patterns_used": [
      {
        "pattern": "Online/Offline Feature Store Split",
        "rationale": "Guarantees training-serving consistency (the #1 cause of ML production bugs) while allowing different latency profiles. Online store serves <5ms lookups; offline store supports batch training reads."
      },
      {
        "pattern": "Model Registry with Blue-Green Deployment",
        "rationale": "Versioned model artifacts with active/candidate/rolled-back states enable instant rollback by simply flipping the active pointer. Inference Service loads both models and can switch traffic without restart."
      },
      {
        "pattern": "Shadow Scoring / Champion-Challenger",
        "rationale": "New candidate model runs in shadow mode alongside the champion for a validation window before full promotion. Provides real-traffic validation without user impact."
      },
      {
        "pattern": "Pre-computed Feature Caching",
        "rationale": "Weather and courier load change slowly (minutes, not milliseconds). Pre-computing and caching these features keeps the hot path fast and avoids calling external APIs during checkout."
      },
      {
        "pattern": "Automated Validation Gate with Human Override",
        "rationale": "Automated checks (MAE regression, latency regression, feature drift) catch obvious failures. Human override preserves the team's ability to make judgment calls on borderline cases — critical for a 4-person team where ML engineers wear multiple hats."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Prediction Serving",
        "classification": "core",
        "aggregates": ["PredictionRequest (order features → predicted minutes)", "ModelInstance (loaded model + version + health status)"]
      },
      {
        "name": "Feature Engineering",
        "classification": "core",
        "aggregates": ["FeatureDefinition (name, transform, source)", "FeatureVector (computed values for a given order context)", "FeatureStore (online + offline materialization)"]
      },
      {
        "name": "Model Lifecycle",
        "classification": "supporting",
        "aggregates": ["ModelVersion (artifact, metrics, status, lineage)", "TrainingRun (dataset hash, hyperparameters, results)", "PromotionDecision (gate results, who approved, rollback history)"]
      },
      {
        "name": "Delivery Data",
        "classification": "generic",
        "aggregates": ["DeliveryOutcome (order_id, predicted_time, actual_time, features_at_prediction_time)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Feature Engineering",
        "downstream": "Prediction Serving",
        "relationship": "Open Host Service — Feature Service exposes a stable API; Inference Service consumes it without influencing feature definitions"
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Model Lifecycle (Training Pipeline)",
        "relationship": "Published Language — offline feature store provides a versioned dataset contract (schema + partitioning) that training consumes"
      },
      {
        "upstream": "Model Lifecycle",
        "downstream": "Prediction Serving",
        "relationship": "Customer-Supplier — Model Registry publishes artifacts; Inference Service consumes them on its own schedule (pull-based with event notification)"
      },
      {
        "upstream": "Delivery Data",
        "downstream": "Feature Engineering",
        "relationship": "Conformist — Feature Engineering conforms to the delivery outcome schema defined by the operational system"
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "In-process model loading (embedded inference) vs. separate model serving infrastructure (e.g., TF Serving, Triton)",
      "gains": "Eliminates a network hop on the hot path (~10-30ms saved), simpler deployment for a 4-person team, fewer moving parts to operate",
      "sacrifices": "Tighter coupling between application code and ML framework, model size limited by service memory, harder to support multiple frameworks simultaneously",
      "alternatives_considered": ["Dedicated model server (TF Serving / Triton) — better for multi-model, multi-framework shops but adds operational overhead and a network hop that threatens the 100ms SLO", "Sidecar model server — compromise, but still adds IPC latency and operational complexity"]
    },
    {
      "decision": "Pre-computed feature caching (Redis/DynamoDB) vs. real-time feature computation per request",
      "gains": "Predictable sub-5ms feature lookup latency, decouples prediction speed from external API availability (weather, dispatch)",
      "sacrifices": "Features can be 1-5 minutes stale (acceptable for weather and courier load which change slowly), additional infrastructure to maintain the cache refresh pipeline",
      "alternatives_considered": ["Real-time computation — freshest data but adds external API calls to the hot path, risking SLO violations on third-party latency spikes"]
    },
    {
      "decision": "Automated validation gate with human override vs. fully automated promotion",
      "gains": "Catches model regressions before they reach production, preserves human judgment for ambiguous cases, builds team trust in the pipeline",
      "sacrifices": "Slightly slower promotion cycle (hours, not minutes), requires an engineer to review borderline cases",
      "alternatives_considered": ["Fully automated canary — sophisticated but overkill for weekly retraining cadence and a 4-person team", "Fully manual promotion — safe but slow, doesn't scale even to weekly retrains"]
    },
    {
      "decision": "Single model (gradient-boosted trees like LightGBM/XGBoost) vs. deep learning",
      "gains": "GBT models are fast at inference (<5ms), small in memory, interpretable for debugging, and easy for 2 ML engineers to iterate on",
      "sacrifices": "May leave accuracy on the table if complex non-linear interactions exist in the data (though for tabular logistics data, GBTs typically match or beat deep learning)",
      "alternatives_considered": ["Neural network — potentially more accurate for very large datasets, but inference is slower and harder to meet 100ms P99 without GPU serving infrastructure"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Model Algorithm",
      "evolution_path": "The model is a swappable artifact behind a stable interface (feature vector in → minutes out). Team can switch from LightGBM to XGBoost to a neural network without changing the serving infrastructure — only the training pipeline and model artifact format change."
    },
    {
      "area": "Feature Definitions",
      "evolution_path": "Feature store schema is versioned. New features (e.g., traffic data, historical zone performance) can be added by registering a new feature definition and backfilling the offline store. Online store picks up new features on next refresh cycle."
    },
    {
      "area": "Retraining Cadence",
      "evolution_path": "Weekly is the starting point. The pipeline is orchestrated by a scheduler (Airflow/cron) — changing to daily or triggered-on-drift requires only a schedule change, not an architecture change."
    },
    {
      "area": "Rollback Granularity",
      "evolution_path": "Currently model-level rollback. Can evolve to feature-level rollback (revert a feature transform) or dataset-level rollback (retrain on a known-good dataset) by extending the Model Registry's lineage tracking."
    }
  ],

  "rigidity_points": [
    {
      "area": "100ms P99 Latency SLO",
      "reason": "This constraint is load-bearing and drives the entire hot-path architecture: in-process inference, pre-computed features, no external API calls at prediction time. Relaxing this SLO would open up simpler alternatives; tightening it would require edge deployment or model distillation."
    },
    {
      "area": "Training-Serving Feature Consistency",
      "reason": "The feature store MUST guarantee that the exact same transformation logic produces features for both training and serving. A mismatch here silently degrades model accuracy in production — this is non-negotiable and should be enforced through shared transformation code and integration tests."
    },
    {
      "area": "Model Artifact Contract",
      "reason": "The interface between Training Pipeline and Inference Service (artifact format, input schema, output schema) must be strictly versioned. Breaking this contract takes down predictions at checkout."
    }
  ],

  "risks": [
    {
      "risk": "Training-serving skew: features computed differently in training (batch) vs serving (online), causing silent accuracy degradation",
      "severity": "critical",
      "mitigation": "Single source of truth for feature transformations (shared library used by both online and offline paths). Integration tests that compare online vs offline feature values for the same input. Log prediction-time features and periodically diff against offline recomputation."
    },
    {
      "risk": "Model degradation goes undetected: new model performs worse on a subpopulation (e.g., a specific zone or time-of-day) not caught by aggregate metrics",
      "severity": "high",
      "mitigation": "Slice-level validation in the Validation Gate — evaluate MAE per zone, per time-of-day bucket, per weight class. Alert on any slice regression beyond threshold, not just aggregate."
    },
    {
      "risk": "Feature store (online cache) becomes stale or unavailable, causing stale or failed predictions during checkout",
      "severity": "high",
      "mitigation": "Feature Service returns last-known-good values with a staleness indicator. Inference Service has a fallback: if features are >10 minutes stale, use a simpler heuristic model (zone-based lookup table) as graceful degradation. Monitor staleness as an SLO."
    },
    {
      "risk": "Rollback doesn't fully restore previous behavior because feature definitions changed between model versions",
      "severity": "medium",
      "mitigation": "Model Registry stores not just the model artifact but the feature schema version it was trained on. Rollback includes restoring the matching feature transform version. Test rollback procedure monthly."
    },
    {
      "risk": "4-person team stretched thin across training pipeline, serving infra, feature store, and monitoring",
      "severity": "medium",
      "mitigation": "Lean heavily on managed services: managed feature store (Feast on managed infra or SageMaker Feature Store), managed orchestration (Airflow/Step Functions), managed model registry (MLflow on managed infra). Minimize custom infrastructure. Clear ownership split: 2 ML engineers own training + features, 2 platform engineers own serving + monitoring."
    },
    {
      "risk": "Latency budget blown by feature lookup or model load time during cold starts or deployments",
      "severity": "medium",
      "mitigation": "Pre-warm inference instances before routing traffic (readiness probe gates on model loaded + feature cache primed). Keep at least 2 instances warm at all times. Model size target: <100MB to ensure fast loads."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (weeks 1-3): Build the Inference Service with a simple heuristic model (zone/distance lookup table) to establish the hot-path latency SLO and API contract with checkout. Stand up the online feature cache (Redis) with weather and courier load refresh. This gets value to production immediately. Phase 2 (weeks 4-6): Build the offline feature store and training pipeline. Train first ML model (LightGBM) on historical data. Set up Model Registry (MLflow) with versioning. Deploy ML model behind the same API, validate it matches or beats the heuristic. Phase 3 (weeks 7-8): Build the Validation Gate with automated metrics checks and human-override promotion flow. Implement monitoring dashboard (predicted vs actual delivery times). Wire up rollback automation. Phase 4 (ongoing): Close the feedback loop — capture actual delivery times, tune features, iterate on model architecture. Add slice-level monitoring. Optimize retraining cadence based on observed drift rates.",
    "files_to_create_or_modify": [
      "services/inference-service/ — stateless prediction API (Python/FastAPI or Go for latency)",
      "services/feature-service/ — online feature serving + cache refresh workers",
      "pipelines/training/ — weekly training job (Python, LightGBM/XGBoost)",
      "pipelines/validation/ — automated model validation gate",
      "libs/features/ — shared feature transformation library (used by both online and offline paths, THIS IS CRITICAL)",
      "infra/model-registry/ — MLflow configuration or equivalent",
      "infra/monitoring/ — dashboards and alert definitions (prediction accuracy, latency, feature drift)",
      "tests/integration/training-serving-consistency/ — integration tests comparing online vs offline feature computation"
    ],
    "patterns_to_follow": "Use the shared feature library (libs/features/) as the single source of truth for ALL feature transformations — both the online serving path and offline training path import from here. This is the most important architectural invariant. Use MLflow (or equivalent) for model versioning — do not build a custom registry. Use a readiness probe pattern for the Inference Service: only accept traffic after model is loaded and feature cache is warm. Use structured logging with prediction_id, model_version, and feature_vector hash on every prediction for debugging and monitoring.",
    "pitfalls_to_avoid": [
      "DO NOT compute features differently in training vs serving — this is the #1 ML production failure mode. Enforce shared code.",
      "DO NOT call external APIs (weather, maps) synchronously during prediction — pre-compute and cache.",
      "DO NOT skip the heuristic fallback — if the ML model or feature store is unavailable, checkout must still work.",
      "DO NOT deploy a new model without slice-level validation — aggregate MAE can hide zone-specific regressions.",
      "DO NOT store models as blobs without metadata — every model version needs: training dataset hash, feature schema version, validation metrics, training hyperparameters.",
      "DO NOT auto-promote without a bake period — run the candidate in shadow mode for at least a few hours before switching traffic.",
      "DO NOT build custom infrastructure where managed services exist — a 4-person team cannot afford to operate Kubernetes ML serving clusters."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "Hot-path architecture (in-process inference + pre-computed features) is well-proven for tabular ML at <100ms P99",
      "Model registry with blue-green rollback is the industry standard pattern for model lifecycle management",
      "Training-serving consistency via shared feature library is the critical architectural invariant",
      "Team sizing guidance — managed services are essential for a 4-person team"
    ],
    "low_confidence_areas": [
      "Exact model algorithm choice (LightGBM vs XGBoost vs other) — depends on data characteristics the ML engineers will discover during experimentation",
      "Feature refresh cadence for online store — 1-5 minutes is a starting estimate, may need tuning based on courier load volatility",
      "Whether the 100ms P99 budget is achievable end-to-end including network to/from checkout service — depends on deployment topology"
    ],
    "assumptions": [
      "The prediction is called from a backend checkout service (not directly from a client), so network latency between checkout and inference is low (<10ms)",
      "Historical delivery data exists in sufficient quantity (tens of thousands of deliveries) to train a meaningful model",
      "Weather and courier load data are available via existing internal or third-party APIs",
      "The team has access to a cloud provider with managed ML services (AWS SageMaker, GCP Vertex, or equivalent)",
      "Tabular gradient-boosted trees will be competitive with deep learning for this problem — standard assumption for structured logistics data"
    ]
  }
}

